export const SUPER_ADMIN = {
  email: "superadmin@carwash.com",
  password: "superadmin123",
};

export const TENANT_USER = {
  email: "carlos@demo-carwash.com",
  password: "password123",
  slug: "demo",
};

export const APP_DOMAIN = "localhost:3000";

export const TENANT_BASE_URL = `http://${TENANT_USER.slug}.${APP_DOMAIN}`;

export const E2E_EMPLOYEE_CODE_PREFIX = "e2e_emp";

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import PageHeader from "@/components/layout/PageHeader";
import Button from "@/components/ui/Button";
import Input from "@/components/ui/Input";
import Card from "@/components/ui/Card";
import Spinner from "@/components/ui/Spinner";
import { formatCurrency } from "@/lib/utils";
import { VEHICLE_TYPE_LABELS } from "@/lib/utils/constants";
import { useDebounce } from "@/hooks/useDebounce";
import Alert from "@/components/ui/Alert";
import { ArrowLeft, ArrowRight, Check, Search, UserCheck, UserPlus, X } from "lucide-react";

interface VehicleItem {
  id: string;
  plate: string;
  brand: string;
  model: string;
  vehicleType: string;
}

interface Client {
  id: string;
  firstName: string;
  lastName: string;
  phone: string;
  vehicles: Array<{ vehicle: VehicleItem }>;
}

interface Employee {
  id: string;
  role: string;
  user: { id: string; name: string | null; email: string };
}

interface ServiceType {
  id: string;
  name: string;
  description: string | null;
  price: string;
  duration: number;
}

interface SelectedService {
  serviceTypeId: string;
  name: string;
  price: number;
  quantity: number;
}

const STEPS = ["Cliente", "Vehiculo", "Lavador", "Servicios", "Confirmar"];

export default function NewOrderPage() {
  const router = useRouter();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  // Step 1: Client
  const [clientSearch, setClientSearch] = useState("");
  const [clients, setClients] = useState<Client[]>([]);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);

  // Step 2: Vehicle
  const [selectedVehicleId, setSelectedVehicleId] = useState("");

  // Step 3: Employee (lavador)
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [employeesLoading, setEmployeesLoading] = useState(false);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string | null>(null);

  // Step 4: Services
  const [services, setServices] = useState<ServiceType[]>([]);
  const [selectedServices, setSelectedServices] = useState<SelectedService[]>([]);

  // Quick registration
  const [showQuickRegister, setShowQuickRegister] = useState(false);
  const [quickForm, setQuickForm] = useState({ firstName: "", lastName: "", phone: "", plate: "" });
  const [quickSaving, setQuickSaving] = useState(false);
  const [quickError, setQuickError] = useState("");

  // Step 5: Notes + submit
  const [notes, setNotes] = useState("");
  const [error, setError] = useState("");

  const debouncedSearch = useDebounce(clientSearch, 300);

  useEffect(() => {
    fetch("/api/services?active=true")
      .then((r) => {
        if (!r.ok) throw new Error("Error al cargar servicios");
        return r.json();
      })
      .then((data) => setServices(Array.isArray(data) ? data : []))
      .catch((err) => setError(err.message || "Error al cargar servicios"));
  }, []);

  useEffect(() => {
    if (debouncedSearch.trim().length < 3) {
      setClients([]);
      return;
    }
    setLoading(true);
    fetch(`/api/clients?search=${encodeURIComponent(debouncedSearch)}&page=1`)
      .then((r) => r.json())
      .then((data) => {
        setClients(data.clients || []);
      })
      .finally(() => setLoading(false));
  }, [debouncedSearch]);

  // Load employees when reaching step 3
  useEffect(() => {
    if (step !== 3) return;
    setEmployeesLoading(true);
    fetch("/api/tenant/team")
      .then((r) => r.json())
      .then((data) => setEmployees(Array.isArray(data) ? data : []))
      .catch(() => setEmployees([]))
      .finally(() => setEmployeesLoading(false));
  }, [step]);

  const selectClient = async (client: Client) => {
    const res = await fetch(`/api/clients/${client.id}`);
    const data = await res.json();
    setSelectedClient(data);
    setStep(2);
  };

  const toggleService = (svc: ServiceType) => {
    const exists = selectedServices.find((s) => s.serviceTypeId === svc.id);
    if (exists) {
      setSelectedServices(selectedServices.filter((s) => s.serviceTypeId !== svc.id));
    } else {
      setSelectedServices([...selectedServices, {
        serviceTypeId: svc.id,
        name: svc.name,
        price: Number(svc.price),
        quantity: 1,
      }]);
    }
  };

  const total = selectedServices.reduce((sum, s) => sum + s.price * s.quantity, 0);

  const clientVehicles = selectedClient?.vehicles.map((cv) => cv.vehicle) || [];

  const selectedAssignee = employees.find((e) => e.user.id === selectedAssigneeId);

  const handleQuickRegister = async () => {
    const { firstName, lastName, phone, plate } = quickForm;
    if (!firstName.trim() || !lastName.trim() || !phone.trim() || !plate.trim()) {
      setQuickError("Todos los campos son obligatorios");
      return;
    }
    setQuickSaving(true);
    setQuickError("");
    try {
      const res = await fetch("/api/clients", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          firstName: firstName.trim(),
          lastName: lastName.trim(),
          phone: phone.trim(), isFrequent:false,
          vehicle: { plate: plate.trim().toUpperCase(), brand: "-", model: "-", vehicleType: "SEDAN" },
        }),
      });
      const created = await res.json();
      if (!res.ok) {
        setQuickError(created.error || "Error al registrar");
        return;
      }
      const clientRes = await fetch(`/api/clients/${created.id}`);
      const clientData = await clientRes.json();
      const newVehicle = clientData.vehicles?.[0]?.vehicle;
      setSelectedClient(clientData);
      if (newVehicle) setSelectedVehicleId(newVehicle.id);
      setShowQuickRegister(false);
      setQuickForm({ firstName: "", lastName: "", phone: "", plate: "" });
      setStep(newVehicle ? 3 : 2);
    } catch {
      setQuickError("Error de conexión");
    } finally {
      setQuickSaving(false);
    }
  };

  const handleSubmit = async () => {
    if (!selectedClient || !selectedVehicleId || selectedServices.length === 0) return;
    setSubmitting(true);
    setError("");
    try {
      const res = await fetch("/api/orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          clientId: selectedClient.id,
          vehicleId: selectedVehicleId,
          assignedToId: selectedAssigneeId || undefined,
          notes: notes || undefined,
          items: selectedServices.map((s) => ({
            serviceTypeId: s.serviceTypeId,
            quantity: s.quantity,
          })),
        }),
      });

      if (res.ok) {
        const data = await res.json();
        router.push(`/orders/${data.id}`);
      } else {
        const data = await res.json();
        setError(data.error || "Error al crear la orden");
        setSubmitting(false);
      }
    } catch {
      setError("Error de conexion. Intenta de nuevo.");
      setSubmitting(false);
    }
  };

  return (
    <div>
      <PageHeader title="Nueva Orden" description={`Paso ${step} de ${STEPS.length}`} />

      {error && <Alert variant="error" className="mt-4">{error}</Alert>}

      <div className="mx-auto mt-6 max-w-3xl">
        {/* Progress bar */}
        <div className="mb-8 flex items-center justify-between">
          {STEPS.map((label, i) => (
            <div key={label} className="flex items-center">
              <div className={`flex h-8 w-8 items-center justify-center rounded-full text-sm font-medium ${
                step > i + 1 ? "bg-emerald-500 text-white" : step === i + 1 ? "bg-zinc-900 text-white dark:bg-zinc-100 dark:text-zinc-900" : "bg-slate-200 text-slate-500 dark:bg-slate-700 dark:text-slate-400"
              }`}>
                {step > i + 1 ? <Check className="h-4 w-4" /> : i + 1}
              </div>
              <span className={`ml-2 text-sm ${step === i + 1 ? "font-medium text-slate-900 dark:text-slate-100" : "text-slate-500 dark:text-slate-400"}`}>{label}</span>
              {i < STEPS.length - 1 && <div className="mx-4 h-px w-8 bg-slate-300 dark:bg-slate-700" />}
            </div>
          ))}
        </div>

        {/* Step 1: Select Client */}
        {step === 1 && (
          <Card>
            <h3 className="mb-4 text-base font-semibold text-slate-900 dark:text-slate-100">Seleccionar Cliente</h3>
            <div className="mb-4">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
                <Input
                  placeholder="Escribe al menos 3 letras para buscar..."
                  value={clientSearch}
                  onChange={(e) => setClientSearch(e.target.value)}
                  className="pl-10"
                />
              </div>
              {loading && <div className="mt-2 flex justify-center"><Spinner size="sm" /></div>}
            </div>
            <div className="space-y-2">
              {clients.map((c) => (
                <div
                  key={c.id}
                  className="flex cursor-pointer items-center justify-between rounded-lg border border-slate-200 p-3 transition-colors hover:border-slate-300 hover:bg-slate-50 dark:border-slate-700 dark:hover:border-slate-600 dark:hover:bg-slate-800/50"
                  onClick={() => selectClient(c)}
                >
                  <div>
                    <p className="font-medium text-slate-900 dark:text-slate-100">{c.firstName} {c.lastName}</p>
                    <p className="text-sm text-slate-500 dark:text-slate-400">{c.phone}</p>
                  </div>
                  <ArrowRight className="h-4 w-4 text-slate-400 dark:text-slate-500" />
                </div>
              ))}
              {clients.length === 0 && clientSearch.length >= 3 && !loading && (
                <p className="text-center text-sm text-slate-500 dark:text-slate-400">No se encontraron clientes</p>
              )}
            </div>

            <div className="mt-4 border-t border-slate-200 pt-4 dark:border-slate-700">
              {!showQuickRegister ? (
                <button
                  onClick={() => setShowQuickRegister(true)}
                  className="flex w-full items-center justify-center gap-2 rounded-lg border border-dashed border-slate-300 p-3 text-sm text-slate-500 transition-colors hover:border-slate-400 hover:bg-slate-50 dark:border-slate-600 dark:text-slate-400 dark:hover:bg-slate-800/50"
                >
                  <UserPlus className="h-4 w-4" />
                  Registrar cliente nuevo
                </button>
              ) : (
                <div className="rounded-lg border border-blue-200 bg-blue-50/50 p-4 dark:border-blue-800/50 dark:bg-blue-950/20">
                  <div className="mb-3 flex items-center justify-between">
                    <p className="text-sm font-medium text-slate-700 dark:text-slate-300">Registro rápido</p>
                    <button onClick={() => { setShowQuickRegister(false); setQuickError(""); }} className="text-slate-400 hover:text-slate-600">
                      <X className="h-4 w-4" />
                    </button>
                  </div>
                  {quickError && <p className="mb-2 text-xs text-red-500">{quickError}</p>}
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label className="mb-1 block text-xs text-slate-500">Nombre *</label>
                      <Input
                        placeholder="Juan"
                        value={quickForm.firstName}
                        onChange={(e) => setQuickForm((f) => ({ ...f, firstName: e.target.value }))}
                      />
                    </div>
                    <div>
                      <label className="mb-1 block text-xs text-slate-500">Apellido *</label>
                      <Input
                        placeholder="Pérez"
                        value={quickForm.lastName}
                        onChange={(e) => setQuickForm((f) => ({ ...f, lastName: e.target.value }))}
                      />
                    </div>
                    <div>
                      <label className="mb-1 block text-xs text-slate-500">Teléfono *</label>
                      <Input
                        placeholder="3001234567"
                        value={quickForm.phone}
                        onChange={(e) => setQuickForm((f) => ({ ...f, phone: e.target.value }))}
                      />
                    </div>
                    <div>
                      <label className="mb-1 block text-xs text-slate-500">Placa *</label>
                      <Input
                        placeholder="ABC123"
                        value={quickForm.plate}
                        onChange={(e) => setQuickForm((f) => ({ ...f, plate: e.target.value }))}
                      />
                    </div>
                  </div>
                  <p className="mt-2 text-xs text-slate-400">Los demás datos del vehículo se pueden completar luego.</p>
                  <div className="mt-3 flex justify-end gap-2">
                    <Button variant="secondary" onClick={() => { setShowQuickRegister(false); setQuickError(""); }}>
                      Cancelar
                    </Button>
                    <Button onClick={handleQuickRegister} loading={quickSaving}>
                      Registrar y continuar
                    </Button>
                  </div>
                </div>
              )}
            </div>
          </Card>
        )}

        {/* Step 2: Select Vehicle */}
        {step === 2 && selectedClient && (
          <Card>
            <h3 className="mb-4 text-base font-semibold text-slate-900 dark:text-slate-100">
              Seleccionar Vehículo de {selectedClient.firstName} {selectedClient.lastName}
            </h3>
            {clientVehicles.length === 0 ? (
              <div className="text-center">
                <p className="mb-4 text-slate-500 dark:text-slate-400">Este cliente no tiene vehículos registrados</p>
                <Button onClick={() => router.push(`/vehicles/new?clientId=${selectedClient.id}`)}>
                  Registrar Vehiculo
                </Button>
              </div>
            ) : (
              <div className="space-y-2">
                {clientVehicles.map((v) => (
                  <div
                    key={v.id}
                    className={`flex cursor-pointer items-center justify-between rounded-lg border p-4 transition-colors ${
                      selectedVehicleId === v.id ? "border-zinc-900 bg-zinc-50 dark:border-zinc-100 dark:bg-zinc-900/30" : "border-slate-200 hover:bg-slate-50 dark:border-slate-700 dark:hover:bg-slate-800"
                    }`}
                    onClick={() => setSelectedVehicleId(v.id)}
                  >
                    <div>
                      <p className="font-medium text-slate-900 dark:text-slate-100">{v.plate}</p>
                      <p className="text-sm text-slate-500 dark:text-slate-400">
                        {v.brand} {v.model} - {VEHICLE_TYPE_LABELS[v.vehicleType] || v.vehicleType}
                      </p>
                    </div>
                    {selectedVehicleId === v.id && <Check className="h-5 w-5 text-zinc-900 dark:text-zinc-100" />}
                  </div>
                ))}
              </div>
            )}
            <div className="mt-6 flex justify-between">
              <Button variant="secondary" onClick={() => setStep(1)}><ArrowLeft className="mr-2 h-4 w-4" /> Atras</Button>
              <Button disabled={!selectedVehicleId} onClick={() => setStep(3)}>Siguiente <ArrowRight className="ml-2 h-4 w-4" /></Button>
            </div>
          </Card>
        )}

        {/* Step 3: Select Employee (Lavador) */}
        {step === 3 && (
          <Card>
            <h3 className="mb-1 text-base font-semibold text-slate-900 dark:text-slate-100">Asignar Lavador</h3>
            <p className="mb-4 text-sm text-slate-500 dark:text-slate-400">Opcional — puedes asignarlo después desde el detalle de la orden.</p>

            {employeesLoading ? (
              <div className="flex justify-center py-8"><Spinner size="lg" /></div>
            ) : (
              <div className="space-y-2">
                {/* Sin asignar option */}
                <div
                  className={`flex cursor-pointer items-center gap-3 rounded-lg border p-4 transition-colors ${
                    selectedAssigneeId === null ? "border-zinc-900 bg-zinc-50 dark:border-zinc-100 dark:bg-zinc-900/30" : "border-slate-200 hover:bg-slate-50 dark:border-slate-700 dark:hover:bg-slate-800"
                  }`}
                  onClick={() => setSelectedAssigneeId(null)}
                >
                  <div className="flex h-9 w-9 items-center justify-center rounded-full bg-slate-200 dark:bg-slate-700">
                    <UserCheck className="h-5 w-5 text-slate-400 dark:text-slate-500" />
                  </div>
                  <div className="flex-1">
                    <p className="font-medium text-slate-700 dark:text-slate-300">Sin asignar</p>
                    <p className="text-xs text-slate-400 dark:text-slate-500">La orden quedará pendiente de asignación</p>
                  </div>
                  {selectedAssigneeId === null && <Check className="h-5 w-5 text-zinc-900 dark:text-zinc-100" />}
                </div>

                {employees.map((emp) => (
                  <div
                    key={emp.user.id}
                    className={`flex cursor-pointer items-center gap-3 rounded-lg border p-4 transition-colors ${
                      selectedAssigneeId === emp.user.id ? "border-zinc-900 bg-zinc-50 dark:bg-zinc-900/10 dark:border-zinc-100" : "border-slate-200 hover:bg-slate-50 dark:border-slate-700 dark:hover:bg-slate-800"
                    }`}
                    onClick={() => setSelectedAssigneeId(emp.user.id)}
                  >
                    <div className="flex h-9 w-9 items-center justify-center rounded-full bg-zinc-100 text-sm font-semibold text-zinc-700 dark:bg-zinc-800 dark:text-zinc-300">
                      {(emp.user.name || emp.user.email).charAt(0).toUpperCase()}
                    </div>
                    <div className="flex-1">
                      <p className="font-medium text-slate-900 dark:text-slate-100">{emp.user.name || emp.user.email}</p>
                      <p className="text-xs capitalize text-slate-400 dark:text-slate-500">{emp.role.toLowerCase()}</p>
                    </div>
                    {selectedAssigneeId === emp.user.id && <Check className="h-5 w-5 text-zinc-900 dark:text-zinc-100" />}
                  </div>
                ))}

                {employees.length === 0 && (
                  <p className="py-4 text-center text-sm text-slate-500 dark:text-slate-400">No hay empleados registrados en el equipo</p>
                )}
              </div>
            )}

            <div className="mt-6 flex justify-between">
              <Button variant="secondary" onClick={() => setStep(2)}><ArrowLeft className="mr-2 h-4 w-4" /> Atras</Button>
              <Button onClick={() => setStep(4)}>Siguiente <ArrowRight className="ml-2 h-4 w-4" /></Button>
            </div>
          </Card>
        )}

        {/* Step 4: Select Services */}
        {step === 4 && (
          <Card>
            <h3 className="mb-4 text-base font-semibold text-slate-900 dark:text-slate-100">Seleccionar Servicios</h3>
            <div className="space-y-2">
              {services.map((svc) => {
                const isSelected = selectedServices.some((s) => s.serviceTypeId === svc.id);
                return (
                  <div
                    key={svc.id}
                    className={`flex cursor-pointer items-center justify-between rounded-lg border p-4 transition-colors ${
                      isSelected ? "border-zinc-900 bg-zinc-50 dark:bg-zinc-900/10 dark:border-zinc-100" : "border-slate-200 hover:bg-slate-50 dark:border-slate-700 dark:hover:bg-slate-800"
                    }`}
                    onClick={() => toggleService(svc)}
                  >
                    <div>
                      <p className="font-medium text-slate-900 dark:text-slate-100">{svc.name}</p>
                      <p className="text-sm text-slate-500 dark:text-slate-400">{svc.description} - {svc.duration} min</p>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="font-semibold text-slate-900 dark:text-slate-100">{formatCurrency(svc.price)}</span>
                      {isSelected && <Check className="h-5 w-5 text-zinc-900 dark:text-zinc-100" />}
                    </div>
                  </div>
                );
              })}
            </div>
            {selectedServices.length > 0 && (
              <div className="mt-4 rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="text-sm text-slate-600 dark:text-slate-400">Servicios seleccionados: {selectedServices.length}</p>
                <p className="text-xl font-bold text-slate-900 dark:text-slate-100">Total: {formatCurrency(total)}</p>
              </div>
            )}
            <div className="mt-6 flex justify-between">
              <Button variant="secondary" onClick={() => setStep(3)}><ArrowLeft className="mr-2 h-4 w-4" /> Atras</Button>
              <Button disabled={selectedServices.length === 0} onClick={() => setStep(5)}>
                Siguiente <ArrowRight className="ml-2 h-4 w-4" />
              </Button>
            </div>
          </Card>
        )}

        {/* Step 5: Confirm */}
        {step === 5 && selectedClient && (
          <Card>
            <h3 className="mb-4 text-base font-semibold text-slate-900 dark:text-slate-100">Confirmar Orden</h3>
            <div className="space-y-3">
              <div className="rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="text-xs text-slate-500 dark:text-slate-400">Cliente</p>
                <p className="mt-0.5 font-medium text-slate-900 dark:text-slate-100">{selectedClient.firstName} {selectedClient.lastName}</p>
              </div>
              <div className="rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="text-xs text-slate-500 dark:text-slate-400">Vehículo</p>
                <p className="mt-0.5 font-medium text-slate-900 dark:text-slate-100">
                  {clientVehicles.find((v) => v.id === selectedVehicleId)?.plate} -{" "}
                  {clientVehicles.find((v) => v.id === selectedVehicleId)?.brand}{" "}
                  {clientVehicles.find((v) => v.id === selectedVehicleId)?.model}
                </p>
              </div>
              <div className="rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="text-xs text-slate-500 dark:text-slate-400">Lavador asignado</p>
                <p className="mt-0.5 font-medium text-slate-900 dark:text-slate-100">
                  {selectedAssignee
                    ? (selectedAssignee.user.name || selectedAssignee.user.email)
                    : <span className="text-slate-400 dark:text-slate-500">Sin asignar</span>}
                </p>
              </div>
              <div className="rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="mb-2 text-xs text-slate-500 dark:text-slate-400">Servicios</p>
                {selectedServices.map((s) => (
                  <div key={s.serviceTypeId} className="flex justify-between py-1 text-sm text-slate-700 dark:text-slate-300">
                    <span>{s.name} x{s.quantity}</span>
                    <span className="font-medium">{formatCurrency(s.price * s.quantity)}</span>
                  </div>
                ))}
                <div className="mt-2 border-t border-slate-200 pt-2 dark:border-slate-700">
                  <div className="flex justify-between text-lg font-bold">
                    <span className="text-slate-900 dark:text-slate-100">Total</span>
                    <span className="text-slate-900 dark:text-slate-100">{formatCurrency(total)}</span>
                  </div>
                </div>
              </div>
              <div>
                <label className="mb-1.5 block text-sm font-medium text-slate-700 dark:text-slate-300">Notas (opcional)</label>
                <textarea
                  className="w-full rounded-md border border-slate-300 p-3 text-sm text-slate-900 placeholder:text-slate-400 focus:border-zinc-900 focus:outline-none focus:ring-2 focus:ring-zinc-900/10 dark:border-slate-700 dark:bg-slate-800 dark:text-slate-100 dark:placeholder:text-slate-500 dark:focus:border-zinc-300 dark:focus:ring-zinc-300/10"
                  rows={3}
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Observaciones adicionales..."
                />
              </div>
            </div>
            <div className="mt-6 flex justify-between">
              <Button variant="secondary" onClick={() => setStep(4)}><ArrowLeft className="mr-2 h-4 w-4" /> Atras</Button>
              <Button onClick={handleSubmit} loading={submitting}>
                <Check className="mr-2 h-4 w-4" /> Crear Orden
              </Button>
            </div>
          </Card>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import PageHeader from "@/components/layout/PageHeader";
import Button from "@/components/ui/Button";
import Input from "@/components/ui/Input";
import Card from "@/components/ui/Card";
import Spinner from "@/components/ui/Spinner";
import { formatCurrency } from "@/lib/utils";
import { VEHICLE_TYPE_LABELS } from "@/lib/utils/constants";
import { useDebounce } from "@/hooks/useDebounce";
import Alert from "@/components/ui/Alert";
import { ArrowLeft, ArrowRight, Check, Search, UserCheck, UserPlus, X } from "lucide-react";

interface VehicleItem {
  id: string;
  plate: string;
  brand: string;
  model: string;
  vehicleType: string;
}

interface Client {
  id: string;
  firstName: string;
  lastName: string;
  phone: string;
  vehicles: Array<{ vehicle: VehicleItem }>;
}

interface Employee {
  id: string;
  role: string;
  isActive: boolean;
  user: { id: string; name: string | null; email: string };
}

interface ServiceType {
  id: string;
  name: string;
  description: string | null;
  price: string;
  duration: number;
}

interface SelectedService {
  serviceTypeId: string;
  name: string;
  price: number;
  quantity: number;
}

const STEPS = ["Cliente", "Vehiculo", "Lavador", "Servicios", "Confirmar"];

export default function NewOrderPage() {
  const router = useRouter();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  // Step 1: Client
  const [clientSearch, setClientSearch] = useState("");
  const [clients, setClients] = useState<Client[]>([]);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);

  // Step 2: Vehicle
  const [selectedVehicleId, setSelectedVehicleId] = useState("");

  // Step 3: Employee (lavador)
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [employeesLoading, setEmployeesLoading] = useState(false);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string | null>(null);

  // Step 4: Services
  const [services, setServices] = useState<ServiceType[]>([]);
  const [selectedServices, setSelectedServices] = useState<SelectedService[]>([]);

  // Quick registration
  const [showQuickRegister, setShowQuickRegister] = useState(false);
  const [quickForm, setQuickForm] = useState({ firstName: "", lastName: "", phone: "", plate: "" });
  const [quickSaving, setQuickSaving] = useState(false);
  const [quickError, setQuickError] = useState("");

  // Step 5: Notes + submit
  const [notes, setNotes] = useState("");
  const [error, setError] = useState("");

  const debouncedSearch = useDebounce(clientSearch, 300);

  useEffect(() => {
    fetch("/api/services?active=true")
      .then((r) => {
        if (!r.ok) throw new Error("Error al cargar servicios");
        return r.json();
      })
      .then((data) => setServices(Array.isArray(data) ? data : []))
      .catch((err) => setError(err.message || "Error al cargar servicios"));
  }, []);

  useEffect(() => {
    if (debouncedSearch.trim().length < 3) {
      setClients([]);
      return;
    }
    setLoading(true);
    fetch(`/api/clients?search=${encodeURIComponent(debouncedSearch)}&page=1`)
      .then((r) => r.json())
      .then((data) => {
        setClients(data.clients || []);
      })
      .finally(() => setLoading(false));
  }, [debouncedSearch]);

  // Load employees when reaching step 3
  useEffect(() => {
    if (step !== 3) return;
    setEmployeesLoading(true);
    fetch("/api/tenant/team")
      .then((r) => r.json())
      .then((data) => {
        const teamMembers = Array.isArray(data) ? data : [];
        const activeEmployees = teamMembers.filter((member) => member?.role === "EMPLOYEE" && member?.isActive);
        setEmployees(activeEmployees);
      })
      .catch(() => setEmployees([]))
      .finally(() => setEmployeesLoading(false));
  }, [step]);

  const selectClient = async (client: Client) => {
    const res = await fetch(`/api/clients/${client.id}`);
    const data = await res.json();
    setSelectedClient(data);
    setStep(2);
  };

  const toggleService = (svc: ServiceType) => {
    const exists = selectedServices.find((s) => s.serviceTypeId === svc.id);
    if (exists) {
      setSelectedServices(selectedServices.filter((s) => s.serviceTypeId !== svc.id));
    } else {
      setSelectedServices([...selectedServices, {
        serviceTypeId: svc.id,
        name: svc.name,
        price: Number(svc.price),
        quantity: 1,
      }]);
    }
  };

  const total = selectedServices.reduce((sum, s) => sum + s.price * s.quantity, 0);

  const clientVehicles = selectedClient?.vehicles.map((cv) => cv.vehicle) || [];

  const selectedAssignee = employees.find((e) => e.user.id === selectedAssigneeId);

  const handleQuickRegister = async () => {
    const { firstName, lastName, phone, plate } = quickForm;
    if (!firstName.trim() || !lastName.trim() || !phone.trim() || !plate.trim()) {
      setQuickError("Todos los campos son obligatorios");
      return;
    }
    setQuickSaving(true);
    setQuickError("");
    try {
      const res = await fetch("/api/clients", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          firstName: firstName.trim(),
          lastName: lastName.trim(),
          phone: phone.trim(),
          vehicle: { plate: plate.trim().toUpperCase(), brand: "-", model: "-", vehicleType: "SEDAN" },
        }),
      });
      const created = await res.json();
      if (!res.ok) {
        setQuickError(created.error || "Error al registrar");
        return;
      }
      const clientRes = await fetch(`/api/clients/${created.id}`);
      const clientData = await clientRes.json();
      const newVehicle = clientData.vehicles?.[0]?.vehicle;
      setSelectedClient(clientData);
      if (newVehicle) setSelectedVehicleId(newVehicle.id);
      setShowQuickRegister(false);
      setQuickForm({ firstName: "", lastName: "", phone: "", plate: "" });
      setStep(newVehicle ? 3 : 2);
    } catch {
      setQuickError("Error de conexión");
    } finally {
      setQuickSaving(false);
    }
  };

  const handleSubmit = async () => {
    if (!selectedClient || !selectedVehicleId || selectedServices.length === 0) return;
    setSubmitting(true);
    setError("");
    try {
      const res = await fetch("/api/orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          clientId: selectedClient.id,
          vehicleId: selectedVehicleId,
          assignedToId: selectedAssigneeId || undefined,
          notes: notes || undefined,
          items: selectedServices.map((s) => ({
            serviceTypeId: s.serviceTypeId,
            quantity: s.quantity,
          })),
        }),
      });

      if (res.ok) {
        const data = await res.json();
        router.push(`/orders/${data.id}`);
      } else {
        const data = await res.json();
        setError(data.error || "Error al crear la orden");
        setSubmitting(false);
      }
    } catch {
      setError("Error de conexion. Intenta de nuevo.");
      setSubmitting(false);
    }
  };

  return (
    <div>
      <PageHeader title="Nueva Orden" description={`Paso ${step} de ${STEPS.length}`} />

      {error && <Alert variant="error" className="mt-4">{error}</Alert>}

      <div className="mx-auto mt-6 max-w-3xl">
        {/* Progress bar */}
        <div className="mb-8 flex items-center justify-between">
          {STEPS.map((label, i) => (
            <div key={label} className="flex items-center">
              <div className={`flex h-8 w-8 items-center justify-center rounded-full text-sm font-medium ${
                step > i + 1 ? "bg-emerald-500 text-white" : step === i + 1 ? "bg-zinc-900 text-white dark:bg-zinc-100 dark:text-zinc-900" : "bg-slate-200 text-slate-500 dark:bg-slate-700 dark:text-slate-400"
              }`}>
                {step > i + 1 ? <Check className="h-4 w-4" /> : i + 1}
              </div>
              <span className={`ml-2 text-sm ${step === i + 1 ? "font-medium text-slate-900 dark:text-slate-100" : "text-slate-500 dark:text-slate-400"}`}>{label}</span>
              {i < STEPS.length - 1 && <div className="mx-4 h-px w-8 bg-slate-300 dark:bg-slate-700" />}
            </div>
          ))}
        </div>

        {/* Step 1: Select Client */}
        {step === 1 && (
          <Card>
            <h3 className="mb-4 text-base font-semibold text-slate-900 dark:text-slate-100">Seleccionar Cliente</h3>
            <div className="mb-4">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
                <Input
                  placeholder="Escribe al menos 3 letras para buscar..."
                  value={clientSearch}
                  onChange={(e) => setClientSearch(e.target.value)}
                  className="pl-10"
                />
              </div>
              {loading && <div className="mt-2 flex justify-center"><Spinner size="sm" /></div>}
            </div>
            <div className="space-y-2">
              {clients.map((c) => (
                <div
                  key={c.id}
                  className="flex cursor-pointer items-center justify-between rounded-lg border border-slate-200 p-3 transition-colors hover:border-slate-300 hover:bg-slate-50 dark:border-slate-700 dark:hover:border-slate-600 dark:hover:bg-slate-800/50"
                  onClick={() => selectClient(c)}
                >
                  <div>
                    <p className="font-medium text-slate-900 dark:text-slate-100">{c.firstName} {c.lastName}</p>
                    <p className="text-sm text-slate-500 dark:text-slate-400">{c.phone}</p>
                  </div>
                  <ArrowRight className="h-4 w-4 text-slate-400 dark:text-slate-500" />
                </div>
              ))}
              {clients.length === 0 && clientSearch.length >= 3 && !loading && (
                <p className="text-center text-sm text-slate-500 dark:text-slate-400">No se encontraron clientes</p>
              )}
            </div>

            <div className="mt-4 border-t border-slate-200 pt-4 dark:border-slate-700">
              {!showQuickRegister ? (
                <button
                  onClick={() => setShowQuickRegister(true)}
                  className="flex w-full items-center justify-center gap-2 rounded-lg border border-dashed border-slate-300 p-3 text-sm text-slate-500 transition-colors hover:border-slate-400 hover:bg-slate-50 dark:border-slate-600 dark:text-slate-400 dark:hover:bg-slate-800/50"
                >
                  <UserPlus className="h-4 w-4" />
                  Registrar cliente nuevo
                </button>
              ) : (
                <div className="rounded-lg border border-blue-200 bg-blue-50/50 p-4 dark:border-blue-800/50 dark:bg-blue-950/20">
                  <div className="mb-3 flex items-center justify-between">
                    <p className="text-sm font-medium text-slate-700 dark:text-slate-300">Registro rápido</p>
                    <button onClick={() => { setShowQuickRegister(false); setQuickError(""); }} className="text-slate-400 hover:text-slate-600">
                      <X className="h-4 w-4" />
                    </button>
                  </div>
                  {quickError && <p className="mb-2 text-xs text-red-500">{quickError}</p>}
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label className="mb-1 block text-xs text-slate-500">Nombre *</label>
                      <Input
                        placeholder="Juan"
                        value={quickForm.firstName}
                        onChange={(e) => setQuickForm((f) => ({ ...f, firstName: e.target.value }))}
                      />
                    </div>
                    <div>
                      <label className="mb-1 block text-xs text-slate-500">Apellido *</label>
                      <Input
                        placeholder="Pérez"
                        value={quickForm.lastName}
                        onChange={(e) => setQuickForm((f) => ({ ...f, lastName: e.target.value }))}
                      />
                    </div>
                    <div>
                      <label className="mb-1 block text-xs text-slate-500">Teléfono *</label>
                      <Input
                        placeholder="3001234567"
                        value={quickForm.phone}
                        onChange={(e) => setQuickForm((f) => ({ ...f, phone: e.target.value }))}
                      />
                    </div>
                    <div>
                      <label className="mb-1 block text-xs text-slate-500">Placa *</label>
                      <Input
                        placeholder="ABC123"
                        value={quickForm.plate}
                        onChange={(e) => setQuickForm((f) => ({ ...f, plate: e.target.value }))}
                      />
                    </div>
                  </div>
                  <p className="mt-2 text-xs text-slate-400">Los demás datos del vehículo se pueden completar luego.</p>
                  <div className="mt-3 flex justify-end gap-2">
                    <Button variant="secondary" onClick={() => { setShowQuickRegister(false); setQuickError(""); }}>
                      Cancelar
                    </Button>
                    <Button onClick={handleQuickRegister} loading={quickSaving}>
                      Registrar y continuar
                    </Button>
                  </div>
                </div>
              )}
            </div>
          </Card>
        )}

        {/* Step 2: Select Vehicle */}
        {step === 2 && selectedClient && (
          <Card>
            <h3 className="mb-4 text-base font-semibold text-slate-900 dark:text-slate-100">
              Seleccionar Vehículo de {selectedClient.firstName} {selectedClient.lastName}
            </h3>
            {clientVehicles.length === 0 ? (
              <div className="text-center">
                <p className="mb-4 text-slate-500 dark:text-slate-400">Este cliente no tiene vehículos registrados</p>
                <Button onClick={() => router.push(`/vehicles/new?clientId=${selectedClient.id}`)}>
                  Registrar Vehiculo
                </Button>
              </div>
            ) : (
              <div className="space-y-2">
                {clientVehicles.map((v) => (
                  <div
                    key={v.id}
                    className={`flex cursor-pointer items-center justify-between rounded-lg border p-4 transition-colors ${
                      selectedVehicleId === v.id ? "border-zinc-900 bg-zinc-50 dark:border-zinc-100 dark:bg-zinc-900/30" : "border-slate-200 hover:bg-slate-50 dark:border-slate-700 dark:hover:bg-slate-800"
                    }`}
                    onClick={() => setSelectedVehicleId(v.id)}
                  >
                    <div>
                      <p className="font-medium text-slate-900 dark:text-slate-100">{v.plate}</p>
                      <p className="text-sm text-slate-500 dark:text-slate-400">
                        {v.brand} {v.model} - {VEHICLE_TYPE_LABELS[v.vehicleType] || v.vehicleType}
                      </p>
                    </div>
                    {selectedVehicleId === v.id && <Check className="h-5 w-5 text-zinc-900 dark:text-zinc-100" />}
                  </div>
                ))}
              </div>
            )}
            <div className="mt-6 flex justify-between">
              <Button variant="secondary" onClick={() => setStep(1)}><ArrowLeft className="mr-2 h-4 w-4" /> Atras</Button>
              <Button disabled={!selectedVehicleId} onClick={() => setStep(3)}>Siguiente <ArrowRight className="ml-2 h-4 w-4" /></Button>
            </div>
          </Card>
        )}

        {/* Step 3: Select Employee (Lavador) */}
        {step === 3 && (
          <Card>
            <h3 className="mb-1 text-base font-semibold text-slate-900 dark:text-slate-100">Asignar Lavador</h3>
            <p className="mb-4 text-sm text-slate-500 dark:text-slate-400">Opcional — puedes asignarlo después desde el detalle de la orden.</p>

            {employeesLoading ? (
              <div className="flex justify-center py-8"><Spinner size="lg" /></div>
            ) : (
              <div className="space-y-2">
                {/* Sin asignar option */}
                <div
                  className={`flex cursor-pointer items-center gap-3 rounded-lg border p-4 transition-colors ${
                    selectedAssigneeId === null ? "border-zinc-900 bg-zinc-50 dark:border-zinc-100 dark:bg-zinc-900/30" : "border-slate-200 hover:bg-slate-50 dark:border-slate-700 dark:hover:bg-slate-800"
                  }`}
                  onClick={() => setSelectedAssigneeId(null)}
                >
                  <div className="flex h-9 w-9 items-center justify-center rounded-full bg-slate-200 dark:bg-slate-700">
                    <UserCheck className="h-5 w-5 text-slate-400 dark:text-slate-500" />
                  </div>
                  <div className="flex-1">
                    <p className="font-medium text-slate-700 dark:text-slate-300">Sin asignar</p>
                    <p className="text-xs text-slate-400 dark:text-slate-500">La orden quedará pendiente de asignación</p>
                  </div>
                  {selectedAssigneeId === null && <Check className="h-5 w-5 text-zinc-900 dark:text-zinc-100" />}
                </div>

                {employees.map((emp) => (
                  <div
                    key={emp.user.id}
                    className={`flex cursor-pointer items-center gap-3 rounded-lg border p-4 transition-colors ${
                      selectedAssigneeId === emp.user.id ? "border-zinc-900 bg-zinc-50 dark:bg-zinc-900/10 dark:border-zinc-100" : "border-slate-200 hover:bg-slate-50 dark:border-slate-700 dark:hover:bg-slate-800"
                    }`}
                    onClick={() => setSelectedAssigneeId(emp.user.id)}
                  >
                    <div className="flex h-9 w-9 items-center justify-center rounded-full bg-zinc-100 text-sm font-semibold text-zinc-700 dark:bg-zinc-800 dark:text-zinc-300">
                      {(emp.user.name || emp.user.email).charAt(0).toUpperCase()}
                    </div>
                    <div className="flex-1">
                      <p className="font-medium text-slate-900 dark:text-slate-100">{emp.user.name || emp.user.email}</p>
                      <p className="text-xs capitalize text-slate-400 dark:text-slate-500">{emp.role.toLowerCase()}</p>
                    </div>
                    {selectedAssigneeId === emp.user.id && <Check className="h-5 w-5 text-zinc-900 dark:text-zinc-100" />}
                  </div>
                ))}

                {employees.length === 0 && (
                  <p className="py-4 text-center text-sm text-slate-500 dark:text-slate-400">No hay empleados registrados en el equipo</p>
                )}
              </div>
            )}

            <div className="mt-6 flex justify-between">
              <Button variant="secondary" onClick={() => setStep(2)}><ArrowLeft className="mr-2 h-4 w-4" /> Atras</Button>
              <Button onClick={() => setStep(4)}>Siguiente <ArrowRight className="ml-2 h-4 w-4" /></Button>
            </div>
          </Card>
        )}

        {/* Step 4: Select Services */}
        {step === 4 && (
          <Card>
            <h3 className="mb-4 text-base font-semibold text-slate-900 dark:text-slate-100">Seleccionar Servicios</h3>
            <div className="space-y-2">
              {services.map((svc) => {
                const isSelected = selectedServices.some((s) => s.serviceTypeId === svc.id);
                return (
                  <div
                    key={svc.id}
                    className={`flex cursor-pointer items-center justify-between rounded-lg border p-4 transition-colors ${
                      isSelected ? "border-zinc-900 bg-zinc-50 dark:bg-zinc-900/10 dark:border-zinc-100" : "border-slate-200 hover:bg-slate-50 dark:border-slate-700 dark:hover:bg-slate-800"
                    }`}
                    onClick={() => toggleService(svc)}
                  >
                    <div>
                      <p className="font-medium text-slate-900 dark:text-slate-100">{svc.name}</p>
                      <p className="text-sm text-slate-500 dark:text-slate-400">{svc.description} - {svc.duration} min</p>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="font-semibold text-slate-900 dark:text-slate-100">{formatCurrency(svc.price)}</span>
                      {isSelected && <Check className="h-5 w-5 text-zinc-900 dark:text-zinc-100" />}
                    </div>
                  </div>
                );
              })}
            </div>
            {selectedServices.length > 0 && (
              <div className="mt-4 rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="text-sm text-slate-600 dark:text-slate-400">Servicios seleccionados: {selectedServices.length}</p>
                <p className="text-xl font-bold text-slate-900 dark:text-slate-100">Total: {formatCurrency(total)}</p>
              </div>
            )}
            <div className="mt-6 flex justify-between">
              <Button variant="secondary" onClick={() => setStep(3)}><ArrowLeft className="mr-2 h-4 w-4" /> Atras</Button>
              <Button disabled={selectedServices.length === 0} onClick={() => setStep(5)}>
                Siguiente <ArrowRight className="ml-2 h-4 w-4" />
              </Button>
            </div>
          </Card>
        )}

        {/* Step 5: Confirm */}
        {step === 5 && selectedClient && (
          <Card>
            <h3 className="mb-4 text-base font-semibold text-slate-900 dark:text-slate-100">Confirmar Orden</h3>
            <div className="space-y-3">
              <div className="rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="text-xs text-slate-500 dark:text-slate-400">Cliente</p>
                <p className="mt-0.5 font-medium text-slate-900 dark:text-slate-100">{selectedClient.firstName} {selectedClient.lastName}</p>
              </div>
              <div className="rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="text-xs text-slate-500 dark:text-slate-400">Vehículo</p>
                <p className="mt-0.5 font-medium text-slate-900 dark:text-slate-100">
                  {clientVehicles.find((v) => v.id === selectedVehicleId)?.plate} -{" "}
                  {clientVehicles.find((v) => v.id === selectedVehicleId)?.brand}{" "}
                  {clientVehicles.find((v) => v.id === selectedVehicleId)?.model}
                </p>
              </div>
              <div className="rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="text-xs text-slate-500 dark:text-slate-400">Lavador asignado</p>
                <p className="mt-0.5 font-medium text-slate-900 dark:text-slate-100">
                  {selectedAssignee
                    ? (selectedAssignee.user.name || selectedAssignee.user.email)
                    : <span className="text-slate-400 dark:text-slate-500">Sin asignar</span>}
                </p>
              </div>
              <div className="rounded-lg bg-slate-50 p-4 dark:bg-slate-800/50">
                <p className="mb-2 text-xs text-slate-500 dark:text-slate-400">Servicios</p>
                {selectedServices.map((s) => (
                  <div key={s.serviceTypeId} className="flex justify-between py-1 text-sm text-slate-700 dark:text-slate-300">
                    <span>{s.name} x{s.quantity}</span>
                    <span className="font-medium">{formatCurrency(s.price * s.quantity)}</span>
                  </div>
                ))}
                <div className="mt-2 border-t border-slate-200 pt-2 dark:border-slate-700">
                  <div className="flex justify-between text-lg font-bold">
                    <span className="text-slate-900 dark:text-slate-100">Total</span>
                    <span className="text-slate-900 dark:text-slate-100">{formatCurrency(total)}</span>
                  </div>
                </div>
              </div>
              <div>
                <label className="mb-1.5 block text-sm font-medium text-slate-700 dark:text-slate-300">Notas (opcional)</label>
                <textarea
                  className="w-full rounded-md border border-slate-300 p-3 text-sm text-slate-900 placeholder:text-slate-400 focus:border-zinc-900 focus:outline-none focus:ring-2 focus:ring-zinc-900/10 dark:border-slate-700 dark:bg-slate-800 dark:text-slate-100 dark:placeholder:text-slate-500 dark:focus:border-zinc-300 dark:focus:ring-zinc-300/10"
                  rows={3}
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Observaciones adicionales..."
                />
              </div>
            </div>
            <div className="mt-6 flex justify-between">
              <Button variant="secondary" onClick={() => setStep(4)}><ArrowLeft className="mr-2 h-4 w-4" /> Atras</Button>
              <Button onClick={handleSubmit} loading={submitting}>
                <Check className="mr-2 h-4 w-4" /> Crear Orden
              </Button>
            </div>
          </Card>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useSession } from "next-auth/react";
import { Users, UserPlus, Mail, Trash2, Copy, Check } from "lucide-react";
import { OnboardingTour } from "@/components/onboarding/OnboardingTour";
import { PageLoader } from "@/components/ui/Spinner";
import Modal from "@/components/ui/Modal";
import Button from "@/components/ui/Button";
import Alert from "@/components/ui/Alert";

interface TeamMember {
  id: string;
  role: string;
  isActive: boolean;
  employeeCode: string | null;
  user: { id: string; name: string | null; email: string; image: string | null };
}

interface InvitationItem {
  id: string;
  email: string;
  role: string;
  expiresAt: string;
  invitedBy: { name: string | null; email: string };
}

interface CreatedCredentials {
  employeeCode: string;
  pin: string;
  name: string;
}

const ROLE_LABEL: Record<string, string> = {
  OWNER: "Propietario",
  ADMIN: "Admin",
  EMPLOYEE: "Lavador",
};

const ROLE_BADGE: Record<string, string> = {
  OWNER: "bg-slate-900 text-white dark:bg-slate-100 dark:text-slate-900",
  ADMIN: "bg-slate-200 text-slate-800 dark:bg-slate-700 dark:text-slate-200",
  EMPLOYEE: "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400",
};

export default function TeamPage() {
  const { data: session } = useSession();
  const [members, setMembers] = useState<TeamMember[]>([]);
  const [invitations, setInvitations] = useState<InvitationItem[]>([]);
  const [loading, setLoading] = useState(true);

  // Invite admin flow
  const [inviteEmail, setInviteEmail] = useState("");
  const [inviteRole] = useState("ADMIN");
  const [inviting, setInviting] = useState(false);
  const [showInviteModal, setShowInviteModal] = useState(false);

  // Create employee direct flow
  const [showEmployeeModal, setShowEmployeeModal] = useState(false);
  const [empForm, setEmpForm] = useState({ name: "", employeeCode: "", pin: "" });
  const [creatingEmployee, setCreatingEmployee] = useState(false);
  const [createdCredentials, setCreatedCredentials] = useState<CreatedCredentials | null>(null);
  const [copied, setCopied] = useState(false);

  const [message, setMessage] = useState("");
  const [isError, setIsError] = useState(false);
  const [removeModal, setRemoveModal] = useState<{ open: boolean; id: string; name: string }>({
    open: false, id: "", name: "",
  });
  const [removing, setRemoving] = useState(false);

  const currentMember = members.find((m) => m.user.id === session?.user?.id);
  const isOwner = currentMember?.role === "OWNER";
  const isManager = isOwner || currentMember?.role === "ADMIN";

  const inputClass = "h-9 w-full rounded-md border border-slate-200 bg-white px-3 text-sm text-slate-900 placeholder:text-slate-400 transition-colors focus:border-zinc-900 focus:outline-none focus:ring-2 focus:ring-zinc-900/10 dark:border-slate-700 dark:bg-slate-800 dark:text-slate-100 dark:placeholder:text-slate-500 dark:focus:border-zinc-300";

  const loadData = async () => {
    const [membersRes, invitationsRes] = await Promise.all([
      fetch("/api/tenant/team"),
      fetch("/api/tenant/invitations"),
    ]);
    const membersData = await membersRes.json();
    const invitationsData = await invitationsRes.json();
    setMembers(Array.isArray(membersData) ? membersData : []);
    setInvitations(Array.isArray(invitationsData) ? invitationsData : []);
    setLoading(false);
  };

  useEffect(() => { loadData(); }, []);

  const showMessage = (text: string, error = false) => {
    setMessage(text);
    setIsError(error);
  };

  const handleInviteAdmin = async (e: React.FormEvent) => {
    e.preventDefault();
    setInviting(true);
    setMessage("");
    try {
      const res = await fetch("/api/tenant/team", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email: inviteEmail, role: inviteRole }),
      });
      const data = await res.json();
      if (res.ok) {
        if (data.emailError) {
          showMessage(`Invitación creada pero el correo no se pudo enviar. Comparte el enlace manualmente.`, true);
        } else {
          showMessage("Invitación enviada correctamente");
        }
        setInviteEmail("");
        setShowInviteModal(false);
        loadData();
      } else {
        showMessage(data.error || "Error al invitar", true);
      }
    } finally {
      setInviting(false);
    }
  };

  const handleCreateEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setCreatingEmployee(true);
    setMessage("");
    try {
      const res = await fetch("/api/tenant/team/employees", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(empForm),
      });
      const data = await res.json();
      if (res.ok) {
        setCreatedCredentials(data);
        setEmpForm({ name: "", employeeCode: "", pin: "" });
        loadData();
      } else {
        showMessage(data.error || "Error al crear empleado", true);
      }
    } finally {
      setCreatingEmployee(false);
    }
  };

  const copyCredentials = () => {
    if (!createdCredentials) return;
    const text = `Código del lavadero: (tu slug)\nCódigo de empleado: ${createdCredentials.employeeCode}\nPIN: ${createdCredentials.pin}`;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleChangeRole = async (tenantUserId: string, newRole: string) => {
    setMessage("");
    const res = await fetch("/api/tenant/team", {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ tenantUserId, role: newRole }),
    });
    const data = await res.json();
    if (res.ok) {
      showMessage("Rol actualizado");
      loadData();
    } else {
      showMessage(data.error || "Error al cambiar rol", true);
    }
  };

  const confirmRemove = (id: string, name: string) => setRemoveModal({ open: true, id, name });

  const handleRemove = async () => {
    setRemoving(true);
    const res = await fetch(`/api/tenant/team?id=${removeModal.id}`, { method: "DELETE" });
    const data = await res.json();
    setRemoveModal({ open: false, id: "", name: "" });
    setRemoving(false);
    if (res.ok) {
      showMessage("Miembro removido");
      loadData();
    } else {
      showMessage(data.error || "Error al remover", true);
    }
  };

  if (loading) return <PageLoader />;

  return (
    <div className="mx-auto max-w-3xl">
      <OnboardingTour flowKey="team" />
      <div className="mb-6 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Users className="h-5 w-5 text-slate-400 dark:text-slate-500" />
          <h1 className="text-xl font-semibold text-slate-900 dark:text-slate-100">Equipo</h1>
        </div>
        {isManager && (
          <div className="flex gap-2">
            <Button variant="secondary" onClick={() => setShowEmployeeModal(true)}>
              <UserPlus className="mr-1.5 h-4 w-4" />
              Agregar lavador
            </Button>
            {isOwner && (
              <Button variant="secondary" onClick={() => setShowInviteModal(true)}>
                <Mail className="mr-1.5 h-4 w-4" />
                Invitar admin
              </Button>
            )}
          </div>
        )}
      </div>

      {message && (
        <div className="mb-4">
          <Alert variant={isError ? "error" : "success"}>{message}</Alert>
        </div>
      )}

      {/* Members */}
      <div data-onboarding="team-members-list" className="mb-6 rounded-xl border border-slate-200 bg-white dark:border-slate-800 dark:bg-slate-900">
        <div className="border-b border-slate-200 px-4 py-3 dark:border-slate-800">
          <h2 className="text-sm font-semibold text-slate-900 dark:text-slate-100">Miembros ({members.length})</h2>
        </div>
        <div className="divide-y divide-slate-100 dark:divide-slate-800">
          {members.map((m) => (
            <div key={m.id} className="flex items-center justify-between px-4 py-3">
              <div>
                <p className="text-sm font-medium text-slate-900 dark:text-slate-100">{m.user.name || m.user.email}</p>
                {m.employeeCode ? (
                  <p className="text-xs text-slate-500 dark:text-slate-400">Código: <span className="font-mono font-medium">{m.employeeCode}</span></p>
                ) : (
                  <p className="text-xs text-slate-500 dark:text-slate-400">{m.user.email}</p>
                )}
              </div>
              <div className="flex items-center gap-2">
                {isOwner && m.role !== "OWNER" ? (
                  <>
                    <select
                      value={m.role}
                      onChange={(e) => handleChangeRole(m.id, e.target.value)}
                      className="rounded-md border border-slate-200 bg-white px-2 py-1 text-xs text-slate-700 dark:border-slate-700 dark:bg-slate-800 dark:text-slate-300"
                    >
                      <option value="ADMIN">Admin</option>
                      <option value="EMPLOYEE">Lavador</option>
                    </select>
                    <button
                      onClick={() => confirmRemove(m.id, m.user.name || m.user.email)}
                      className="rounded-md p-1.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20"
                      title="Remover miembro"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </>
                ) : (
                  <span className={`rounded-full px-2.5 py-0.5 text-xs font-medium ${ROLE_BADGE[m.role] || ROLE_BADGE.EMPLOYEE}`}>
                    {ROLE_LABEL[m.role] || m.role}
                  </span>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Pending invitations */}
      {invitations.length > 0 && (
        <div className="rounded-xl border border-slate-200 bg-white dark:border-slate-800 dark:bg-slate-900">
          <div className="border-b border-slate-200 px-4 py-3 dark:border-slate-800">
            <h2 className="text-sm font-semibold text-slate-900 dark:text-slate-100">
              Invitaciones Pendientes ({invitations.length})
            </h2>
          </div>
          <div className="divide-y divide-slate-100 dark:divide-slate-800">
            {invitations.map((inv) => (
              <div key={inv.id} className="flex items-center justify-between px-4 py-3">
                <div className="flex items-center gap-2">
                  <Mail className="h-4 w-4 text-slate-400 dark:text-slate-500" />
                  <div>
                    <p className="text-sm font-medium text-slate-900 dark:text-slate-100">{inv.email}</p>
                    <p className="text-xs text-slate-500 dark:text-slate-400">
                      Invitado por {inv.invitedBy.name || inv.invitedBy.email}
                    </p>
                  </div>
                </div>
                <span className="rounded-full bg-amber-100 px-2.5 py-0.5 text-xs font-medium text-amber-700 dark:bg-amber-900/30 dark:text-amber-400">
                  {ROLE_LABEL[inv.role] || inv.role} — Pendiente
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Modal: Agregar lavador */}
      <Modal isOpen={showEmployeeModal} onClose={() => { setShowEmployeeModal(false); setCreatedCredentials(null); }} title="Agregar lavador">
        {createdCredentials ? (
          <div>
            <p className="mb-4 text-sm text-slate-600 dark:text-slate-400">
              Lavador <strong className="text-slate-900 dark:text-slate-100">{createdCredentials.name}</strong> creado. Entrega estas credenciales:
            </p>
            <div className="rounded-lg border border-slate-200 bg-slate-50 p-4 font-mono text-sm dark:border-slate-700 dark:bg-slate-800">
              <p className="text-slate-600 dark:text-slate-400">Código de empleado: <span className="font-semibold text-slate-900 dark:text-slate-100">{createdCredentials.employeeCode}</span></p>
              <p className="mt-1 text-slate-600 dark:text-slate-400">PIN: <span className="font-semibold text-slate-900 dark:text-slate-100">{createdCredentials.pin}</span></p>
            </div>
            <p className="mt-2 text-xs text-slate-400">El lavador necesita también el código del lavadero (slug) para entrar.</p>
            <div className="mt-4 flex justify-between">
              <Button variant="secondary" onClick={copyCredentials}>
                {copied ? <Check className="mr-1.5 h-4 w-4" /> : <Copy className="mr-1.5 h-4 w-4" />}
                {copied ? "Copiado" : "Copiar"}
              </Button>
              <Button onClick={() => { setCreatedCredentials(null); setShowEmployeeModal(false); }}>
                Listo
              </Button>
            </div>
          </div>
        ) : (
          <form onSubmit={handleCreateEmployee} className="space-y-4">
            <div>
              <label className="mb-1 block text-sm font-medium text-slate-700 dark:text-slate-300">Nombre completo *</label>
              <input
                value={empForm.name}
                onChange={(e) => setEmpForm((f) => ({ ...f, name: e.target.value }))}
                placeholder="Juan Pérez"
                required
                className={inputClass}
              />
            </div>
            <div>
              <label className="mb-1 block text-sm font-medium text-slate-700 dark:text-slate-300">Código de empleado *</label>
              <input
                value={empForm.employeeCode}
                onChange={(e) => setEmpForm((f) => ({ ...f, employeeCode: e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, "") }))}
                placeholder="juan01"
                required
                className={inputClass}
              />
              <p className="mt-0.5 text-xs text-slate-400">Solo letras minúsculas, números y guión bajo.</p>
            </div>
            <div>
              <label className="mb-1 block text-sm font-medium text-slate-700 dark:text-slate-300">PIN (4 dígitos) *</label>
              <input
                value={empForm.pin}
                onChange={(e) => setEmpForm((f) => ({ ...f, pin: e.target.value.replace(/\D/g, "").slice(0, 4) }))}
                placeholder="1234"
                required
                inputMode="numeric"
                className={inputClass}
              />
            </div>
            <div className="flex justify-end gap-2 pt-2">
              <Button variant="secondary" type="button" onClick={() => setShowEmployeeModal(false)}>Cancelar</Button>
              <Button type="submit" loading={creatingEmployee} disabled={empForm.pin.length !== 4}>
                Crear lavador
              </Button>
            </div>
          </form>
        )}
      </Modal>

      {/* Modal: Invitar admin */}
      <Modal isOpen={showInviteModal} onClose={() => setShowInviteModal(false)} title="Invitar administrador">
        <form onSubmit={handleInviteAdmin} className="space-y-4">
          <div>
            <label className="mb-1 block text-sm font-medium text-slate-700 dark:text-slate-300">Correo electrónico *</label>
            <input
              type="email"
              value={inviteEmail}
              onChange={(e) => setInviteEmail(e.target.value)}
              placeholder="admin@ejemplo.com"
              required
              className={inputClass}
            />
          </div>
          <div className="flex justify-end gap-2 pt-2">
            <Button variant="secondary" type="button" onClick={() => setShowInviteModal(false)}>Cancelar</Button>
            <Button type="submit" loading={inviting} disabled={!inviteEmail}>
              <Mail className="mr-1.5 h-4 w-4" />
              Enviar invitación
            </Button>
          </div>
        </form>
      </Modal>

      {/* Remove confirmation modal */}
      <Modal
        isOpen={removeModal.open}
        onClose={() => setRemoveModal({ open: false, id: "", name: "" })}
        title="Confirmar eliminación"
      >
        <p className="mb-4 text-sm text-slate-600 dark:text-slate-400">
          ¿Estás seguro de remover a <strong className="text-slate-900 dark:text-slate-100">{removeModal.name}</strong> del equipo?
        </p>
        <div className="flex justify-end gap-3">
          <Button variant="secondary" onClick={() => setRemoveModal({ open: false, id: "", name: "" })}>
            Cancelar
          </Button>
          <Button variant="danger" onClick={handleRemove} loading={removing}>
            Remover
          </Button>
        </div>
      </Modal>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useSession } from "next-auth/react";
import { Users, UserPlus, Mail, Trash2, Copy, Check } from "lucide-react";
import { OnboardingTour } from "@/components/onboarding/OnboardingTour";
import { PageLoader } from "@/components/ui/Spinner";
import Modal from "@/components/ui/Modal";
import Button from "@/components/ui/Button";
import Alert from "@/components/ui/Alert";

interface TeamMember {
  id: string;
  role: string;
  isActive: boolean;
  employeeCode: string | null;
  user: { id: string; name: string | null; email: string; image: string | null };
}

interface InvitationItem {
  id: string;
  email: string;
  role: string;
  expiresAt: string;
  invitedBy: { name: string | null; email: string };
}

interface CreatedCredentials {
  employeeCode: string;
  pin: string;
  name: string;
}

const ROLE_LABEL: Record<string, string> = {
  OWNER: "Propietario",
  ADMIN: "Admin",
  EMPLOYEE: "Lavador",
};

const ROLE_BADGE: Record<string, string> = {
  OWNER: "bg-slate-900 text-white dark:bg-slate-100 dark:text-slate-900",
  ADMIN: "bg-slate-200 text-slate-800 dark:bg-slate-700 dark:text-slate-200",
  EMPLOYEE: "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400",
};

export default function TeamPage() {
  const { data: session } = useSession();
  const [members, setMembers] = useState<TeamMember[]>([]);
  const [invitations, setInvitations] = useState<InvitationItem[]>([]);
  const [loading, setLoading] = useState(true);

  // Invite admin flow
  const [inviteEmail, setInviteEmail] = useState("");
  const [inviteRole] = useState("ADMIN");
  const [inviting, setInviting] = useState(false);
  const [showInviteModal, setShowInviteModal] = useState(false);

  // Create employee direct flow
  const [showEmployeeModal, setShowEmployeeModal] = useState(false);
  const [empForm, setEmpForm] = useState({ name: "", employeeCode: "", pin: "" });
  const [creatingEmployee, setCreatingEmployee] = useState(false);
  const [createdCredentials, setCreatedCredentials] = useState<CreatedCredentials | null>(null);
  const [copied, setCopied] = useState(false);

  const [message, setMessage] = useState("");
  const [isError, setIsError] = useState(false);
  const [removeModal, setRemoveModal] = useState<{ open: boolean; id: string; name: string }>({
    open: false, id: "", name: "",
  });
  const [removing, setRemoving] = useState(false);

  const currentMember = members.find((m) => m.user.id === session?.user?.id);
  const isOwner = currentMember?.role === "OWNER";
  const isManager = isOwner || currentMember?.role === "ADMIN";

  const inputClass = "h-9 w-full rounded-md border border-slate-200 bg-white px-3 text-sm text-slate-900 placeholder:text-slate-400 transition-colors focus:border-zinc-900 focus:outline-none focus:ring-2 focus:ring-zinc-900/10 dark:border-slate-700 dark:bg-slate-800 dark:text-slate-100 dark:placeholder:text-slate-500 dark:focus:border-zinc-300";

  const loadData = async () => {
    const [membersRes, invitationsRes] = await Promise.all([
      fetch("/api/tenant/team"),
      fetch("/api/tenant/invitations"),
    ]);
    const membersData = await membersRes.json();
    const invitationsData = await invitationsRes.json();
    setMembers(Array.isArray(membersData) ? membersData : []);
    setInvitations(Array.isArray(invitationsData) ? invitationsData : []);
    setLoading(false);
  };

  useEffect(() => { loadData(); }, []);

  const showMessage = (text: string, error = false) => {
    setMessage(text);
    setIsError(error);
  };

  const handleInviteAdmin = async (e: React.FormEvent) => {
    e.preventDefault();
    setInviting(true);
    setMessage("");
    try {
      const res = await fetch("/api/tenant/team", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email: inviteEmail, role: inviteRole }),
      });
      const data = await res.json();
      if (res.ok) {
        if (data.emailError) {
          showMessage(`Invitación creada pero el correo no se pudo enviar. Comparte el enlace manualmente.`, true);
        } else {
          showMessage("Invitación enviada correctamente");
        }
        setInviteEmail("");
        setShowInviteModal(false);
        loadData();
      } else {
        showMessage(data.error || "Error al invitar", true);
      }
    } finally {
      setInviting(false);
    }
  };

  const handleCreateEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setCreatingEmployee(true);
    setMessage("");
    try {
      const res = await fetch("/api/tenant/team/employees", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(empForm),
      });
      const data = await res.json();
      if (res.ok) {
        setCreatedCredentials(data);
        setEmpForm({ name: "", employeeCode: "", pin: "" });
        loadData();
      } else {
        showMessage(data.error || "Error al crear empleado", true);
      }
    } catch {
      showMessage("Error de conexión al crear empleado", true);
    } finally {
      setCreatingEmployee(false);
    }
  };

  const copyCredentials = () => {
    if (!createdCredentials) return;
    const tenantCode = session?.user?.tenantSlug || "(tu slug)";
    const text = `Código del lavadero: ${tenantCode}\nCódigo de empleado: ${createdCredentials.employeeCode}\nPIN: ${createdCredentials.pin}`;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleChangeRole = async (tenantUserId: string, newRole: string) => {
    setMessage("");
    const res = await fetch("/api/tenant/team", {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ tenantUserId, role: newRole }),
    });
    const data = await res.json();
    if (res.ok) {
      showMessage("Rol actualizado");
      loadData();
    } else {
      showMessage(data.error || "Error al cambiar rol", true);
    }
  };

  const confirmRemove = (id: string, name: string) => setRemoveModal({ open: true, id, name });

  const handleRemove = async () => {
    setRemoving(true);
    const res = await fetch(`/api/tenant/team?id=${removeModal.id}`, { method: "DELETE" });
    const data = await res.json();
    setRemoveModal({ open: false, id: "", name: "" });
    setRemoving(false);
    if (res.ok) {
      showMessage("Miembro removido");
      loadData();
    } else {
      showMessage(data.error || "Error al remover", true);
    }
  };

  if (loading) return <PageLoader />;

  return (
    <div className="mx-auto max-w-3xl">
      <OnboardingTour flowKey="team" />
      <div className="mb-6 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Users className="h-5 w-5 text-slate-400 dark:text-slate-500" />
          <h1 className="text-xl font-semibold text-slate-900 dark:text-slate-100">Equipo</h1>
        </div>
        {isManager && (
          <div className="flex gap-2">
            <Button variant="secondary" onClick={() => setShowEmployeeModal(true)}>
              <UserPlus className="mr-1.5 h-4 w-4" />
              Agregar lavador
            </Button>
            {isOwner && (
              <Button variant="secondary" onClick={() => setShowInviteModal(true)}>
                <Mail className="mr-1.5 h-4 w-4" />
                Invitar admin
              </Button>
            )}
          </div>
        )}
      </div>

      {message && (
        <div className="mb-4">
          <Alert variant={isError ? "error" : "success"}>{message}</Alert>
        </div>
      )}

      {/* Members */}
      <div data-onboarding="team-members-list" className="mb-6 rounded-xl border border-slate-200 bg-white dark:border-slate-800 dark:bg-slate-900">
        <div className="border-b border-slate-200 px-4 py-3 dark:border-slate-800">
          <h2 className="text-sm font-semibold text-slate-900 dark:text-slate-100">Miembros ({members.length})</h2>
        </div>
        <div className="divide-y divide-slate-100 dark:divide-slate-800">
          {members.map((m) => (
            <div key={m.id} className="flex items-center justify-between px-4 py-3">
              <div>
                <p className="text-sm font-medium text-slate-900 dark:text-slate-100">{m.user.name || m.user.email}</p>
                {m.employeeCode ? (
                  <p className="text-xs text-slate-500 dark:text-slate-400">Código: <span className="font-mono font-medium">{m.employeeCode}</span></p>
                ) : (
                  <p className="text-xs text-slate-500 dark:text-slate-400">{m.user.email}</p>
                )}
              </div>
              <div className="flex items-center gap-2">
                {isOwner && m.role !== "OWNER" ? (
                  <>
                    <select
                      value={m.role}
                      onChange={(e) => handleChangeRole(m.id, e.target.value)}
                      className="rounded-md border border-slate-200 bg-white px-2 py-1 text-xs text-slate-700 dark:border-slate-700 dark:bg-slate-800 dark:text-slate-300"
                    >
                      <option value="ADMIN">Admin</option>
                      <option value="EMPLOYEE">Lavador</option>
                    </select>
                    <button
                      onClick={() => confirmRemove(m.id, m.user.name || m.user.email)}
                      className="rounded-md p-1.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20"
                      title="Remover miembro"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </>
                ) : (
                  <span className={`rounded-full px-2.5 py-0.5 text-xs font-medium ${ROLE_BADGE[m.role] || ROLE_BADGE.EMPLOYEE}`}>
                    {ROLE_LABEL[m.role] || m.role}
                  </span>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Pending invitations */}
      {invitations.length > 0 && (
        <div className="rounded-xl border border-slate-200 bg-white dark:border-slate-800 dark:bg-slate-900">
          <div className="border-b border-slate-200 px-4 py-3 dark:border-slate-800">
            <h2 className="text-sm font-semibold text-slate-900 dark:text-slate-100">
              Invitaciones Pendientes ({invitations.length})
            </h2>
          </div>
          <div className="divide-y divide-slate-100 dark:divide-slate-800">
            {invitations.map((inv) => (
              <div key={inv.id} className="flex items-center justify-between px-4 py-3">
                <div className="flex items-center gap-2">
                  <Mail className="h-4 w-4 text-slate-400 dark:text-slate-500" />
                  <div>
                    <p className="text-sm font-medium text-slate-900 dark:text-slate-100">{inv.email}</p>
                    <p className="text-xs text-slate-500 dark:text-slate-400">
                      Invitado por {inv.invitedBy.name || inv.invitedBy.email}
                    </p>
                  </div>
                </div>
                <span className="rounded-full bg-amber-100 px-2.5 py-0.5 text-xs font-medium text-amber-700 dark:bg-amber-900/30 dark:text-amber-400">
                  {ROLE_LABEL[inv.role] || inv.role} — Pendiente
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Modal: Agregar lavador */}
      <Modal isOpen={showEmployeeModal} onClose={() => { setShowEmployeeModal(false); setCreatedCredentials(null); }} title="Agregar lavador">
        {createdCredentials ? (
          <div>
            <p className="mb-4 text-sm text-slate-600 dark:text-slate-400">
              Lavador <strong className="text-slate-900 dark:text-slate-100">{createdCredentials.name}</strong> creado. Entrega estas credenciales:
            </p>
            <div className="rounded-lg border border-slate-200 bg-slate-50 p-4 font-mono text-sm dark:border-slate-700 dark:bg-slate-800">
              <p className="text-slate-600 dark:text-slate-400">Código de empleado: <span className="font-semibold text-slate-900 dark:text-slate-100">{createdCredentials.employeeCode}</span></p>
              <p className="mt-1 text-slate-600 dark:text-slate-400">PIN: <span className="font-semibold text-slate-900 dark:text-slate-100">{createdCredentials.pin}</span></p>
            </div>
            <p className="mt-2 text-xs text-slate-400">
              El lavador necesita también el código del lavadero ({session?.user?.tenantSlug || "tu slug"}) para entrar.
            </p>
            <div className="mt-4 flex justify-between">
              <Button variant="secondary" onClick={copyCredentials}>
                {copied ? <Check className="mr-1.5 h-4 w-4" /> : <Copy className="mr-1.5 h-4 w-4" />}
                {copied ? "Copiado" : "Copiar"}
              </Button>
              <Button onClick={() => { setCreatedCredentials(null); setShowEmployeeModal(false); }}>
                Listo
              </Button>
            </div>
          </div>
        ) : (
          <form onSubmit={handleCreateEmployee} className="space-y-4">
            <div>
              <label className="mb-1 block text-sm font-medium text-slate-700 dark:text-slate-300">Nombre completo *</label>
              <input
                value={empForm.name}
                onChange={(e) => setEmpForm((f) => ({ ...f, name: e.target.value }))}
                placeholder="Juan Pérez"
                required
                className={inputClass}
              />
            </div>
            <div>
              <label className="mb-1 block text-sm font-medium text-slate-700 dark:text-slate-300">Código de empleado *</label>
              <input
                value={empForm.employeeCode}
                onChange={(e) => setEmpForm((f) => ({ ...f, employeeCode: e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, "") }))}
                placeholder="juan01"
                required
                className={inputClass}
              />
              <p className="mt-0.5 text-xs text-slate-400">Solo letras minúsculas, números y guión bajo.</p>
            </div>
            <div>
              <label className="mb-1 block text-sm font-medium text-slate-700 dark:text-slate-300">PIN (4 dígitos) *</label>
              <input
                value={empForm.pin}
                onChange={(e) => setEmpForm((f) => ({ ...f, pin: e.target.value.replace(/\D/g, "").slice(0, 4) }))}
                placeholder="1234"
                required
                inputMode="numeric"
                className={inputClass}
              />
            </div>
            <div className="flex justify-end gap-2 pt-2">
              <Button variant="secondary" type="button" onClick={() => setShowEmployeeModal(false)}>Cancelar</Button>
              <Button type="submit" loading={creatingEmployee} disabled={empForm.pin.length !== 4}>
                Crear lavador
              </Button>
            </div>
          </form>
        )}
      </Modal>

      {/* Modal: Invitar admin */}
      <Modal isOpen={showInviteModal} onClose={() => setShowInviteModal(false)} title="Invitar administrador">
        <form onSubmit={handleInviteAdmin} className="space-y-4">
          <div>
            <label className="mb-1 block text-sm font-medium text-slate-700 dark:text-slate-300">Correo electrónico *</label>
            <input
              type="email"
              value={inviteEmail}
              onChange={(e) => setInviteEmail(e.target.value)}
              placeholder="admin@ejemplo.com"
              required
              className={inputClass}
            />
          </div>
          <div className="flex justify-end gap-2 pt-2">
            <Button variant="secondary" type="button" onClick={() => setShowInviteModal(false)}>Cancelar</Button>
            <Button type="submit" loading={inviting} disabled={!inviteEmail}>
              <Mail className="mr-1.5 h-4 w-4" />
              Enviar invitación
            </Button>
          </div>
        </form>
      </Modal>

      {/* Remove confirmation modal */}
      <Modal
        isOpen={removeModal.open}
        onClose={() => setRemoveModal({ open: false, id: "", name: "" })}
        title="Confirmar eliminación"
      >
        <p className="mb-4 text-sm text-slate-600 dark:text-slate-400">
          ¿Estás seguro de remover a <strong className="text-slate-900 dark:text-slate-100">{removeModal.name}</strong> del equipo?
        </p>
        <div className="flex justify-end gap-3">
          <Button variant="secondary" onClick={() => setRemoveModal({ open: false, id: "", name: "" })}>
            Cancelar
          </Button>
          <Button variant="danger" onClick={handleRemove} loading={removing}>
            Remover
          </Button>
        </div>
      </Modal>
    </div>
  );
}

import { ApiResponse } from "@/lib/http";
import { requireAuth } from "@/middleware/auth.middleware";
import { requireTenantContext, ensureManagementAccess } from "@/middleware/tenant.middleware";
import { handleTenantHttpError } from "@/modules/tenant/tenant.errors";
import { createDirectEmployeeService } from "@/modules/tenant/services/create-direct-employee.service";
import { z } from "zod";

const createEmployeeSchema = z.object({
  name:         z.string().trim().min(2).max(100),
  employeeCode: z.string().trim().min(2).max(20).toLowerCase().regex(/^[a-z0-9_]+$/, "Solo letras minúsculas, números y guión bajo"),
  pin:          z.string().length(4).regex(/^\d+$/, "El PIN debe ser 4 dígitos numéricos"),
});

export async function POST(request: Request) {
  try {
    const session = await requireAuth();
    const { tenantId, tenant } = await requireTenantContext(request.headers);
    await ensureManagementAccess(session.user.id, tenantId, session.user.globalRole);

    const body = await request.json();
    const data = createEmployeeSchema.parse(body);

    const result = await createDirectEmployeeService({
      tenantId,
      tenantSlug: tenant.slug,
      name: data.name,
      employeeCode: data.employeeCode,
      pin: data.pin,
    });

    return ApiResponse.created(result);
  } catch (error) {
    return handleTenantHttpError(error, "Error al crear empleado:");
  }
}

import { ApiResponse } from "@/lib/http";
